function sanitizeLogInput(input: any): any {
  if (typeof input === 'string') {
    return input.replace(/[\n\r\t]/g, ' ');
  }
  return input;
}

logger.info({ 
  user: sanitizeLogInput(req.user),
  action: sanitizeLogInput(req.body.action) 
