#### **任务 2: WebSocket 安全加固**
**优先级**: 🔴 P0 | **预计工作量**: 2 天

**问题分析**:
- WebSocket 连接未加密
- 缺少消息验证和过滤
- 容易受到注入攻击

**实施方案**:

```typescript
// src/dashboard/services/secure-websocket.service.ts
import { FastifyInstance } from 'fastify'
import { createHash, randomBytes } from 'crypto'

export class SecureWebSocketService {
  private connectedClients: Map<string, WebSocketConnection> = new Map()
  private rateLimiter: Map<string, number[]> = new Map()

  constructor(private fastify: FastifyInstance) {}

  // 生成会话 ID
  private generateSessionId(): string {
    return randomBytes(32).toString('hex')
  }

  // 消息验证（防止注入）
  private validateMessage(data: any): boolean {
    // 白名单验证
    const allowedEvents = [
      'iteration.status_changed',
      'agent.status_changed',
      'iteration.progress',
      'system.metrics'
    ]

    if (!data.event || !allowedEvents.includes(data.event)) {
      return false
    }

    // 数据大小限制
    const dataSize = JSON.stringify(data).length
    if (dataSize > 1024 * 100) { // 100KB
      return false
    }

    return true
  }

  // 速率限制（防止 DDoS）
  private checkRateLimit(sessionId: string): boolean {
    const now = Date.now()
    const window = 60000 // 1 分钟
    const maxMessages = 100

    if (!this.rateLimiter.has(sessionId)) {
      this.rateLimiter.set(sessionId, [])
    }

    const timestamps = this.rateLimiter.get(sessionId)!
    // 清理过期时间戳
    const validTimestamps = timestamps.filter(t => now - t < window)

    if (validTimestamps.length >= maxMessages) {
      return false
    }

    validTimestamps.push(now)
    this.rateLimiter.set(sessionId, validTimestamps)
    return true
  }

  // 安全的消息广播
  broadcast(event: string, data: any) {
    const message = { event, data }

    // 验证消息
    if (!this.validateMessage(message)) {
      console.error('[Security] Invalid message blocked:', event)
      return
    }

    // 广播给所有认证的客户端
    for (const [sessionId, client] of this.connectedClients) {
      if (client.authenticated) {
        try {
          client.socket.send(JSON.stringify(message))
        } catch (error) {
          console.error(`[Security] Failed to send to ${sessionId}:`, error)
          this.disconnect(sessionId)
        }
      }
    }
  }

  // 连接管理
  handleConnection(socket: WebSocket, request: FastifyRequest) {
    const sessionId = this.generateSessionId()

    const connection: WebSocketConnection = {
      socket,
      sessionId,
      authenticated: false,
      user: null,
      createdAt: Date.now()
    }

    this.connectedClients.set(sessionId, connection)

    socket.on('message', (data: Buffer) => {
      if (!this.checkRateLimit(sessionId)) {
        socket.send(JSON.stringify({
          error: 'Rate limit exceeded'
        }))
        return
      }

      try {
        const message = JSON.parse(data.toString())
        // 处理消息...
      } catch (error) {
        console.error('[Security] Invalid message format')
      }
    })

    socket.on('close', () => {
      this.disconnect(sessionId)
    })
  }

  private disconnect(sessionId: string) {
    const client = this.connectedClients.get(sessionId)
    if (client) {
      client.socket.close()
      this.connectedClients.delete(sessionId)
      this.rateLimiter.delete(sessionId)
    }
  }
}
